module RefModule (
    input [4:0] data_in,
    input write_enable,
    input read_enable,
    output reg [4:0] data_out
);
    reg [4:0] unused_stored_data;

    always @(*) begin
        if (write_enable) begin
            unused_stored_data = data_in;
        end
        if (read_enable) begin
            data_out = unused_stored_data;
        end
    end
endmodule
